import json
with open(r'C:\Users\Revexn\Desktop\antigravity\seconde-exp\proverbs_extractor\data\proverbs\social_tokens.json', 'r', encoding='utf-8') as f:
    data = json.load(f)
print('Keys found:', list(data.keys()))
if 'facebook_access_token' in data:
    token = data['facebook_access_token']
    print(f'facebook_access_token: {token[:20]}...{token[-10:]}')
    print(f'Token length: {len(token)}')
else:
    for k, v in data.items():
        if 'facebook' in k.lower() or 'token' in k.lower() or 'access' in k.lower():
            val = str(v)
            print(f'{k}: {val[:20]}...{val[-10:] if len(val) > 20 else val}')
if 'facebook_page_id' in data:
    print(f'facebook_page_id: {data["facebook_page_id"]}')
else:
    for k, v in data.items():
        if 'page' in k.lower() or 'id' in k.lower():
            print(f'{k}: {v}')
print('FULL_TOKEN_START')
print(data.get('facebook_access_token', 'NOT_FOUND'))
print('FULL_TOKEN_END')
print('PAGE_ID:', data.get('facebook_page_id', 'NOT_FOUND'))
